"use client";

// Coordinator module router and feature screens.
// Each function below renders one workspace module (students, schools,
// placements, lesson notes, visits, reports, settings, etc.) using shared
// table, filter, modal and empty-state patterns.
import { useEffect, useState } from "react";
import type { LessonNote, NotificationItem, Placement, Student, Visit } from "@/lib/sip-data";
import { PostInternshipPage } from "@/components/features/PostInternshipPage";
import { BulkUploadPage } from "@/components/features/BulkUploadPage";
import { MessagesPage } from "@/components/features/MessagesPage";
import { CertificatesPage } from "@/components/features/CertificatesPage";
import { AuditLogPage } from "@/components/features/AuditLogPage";
import { RecordActionButtons } from "@/components/RecordActionButtons";
import { AppearanceSettings } from "@/components/AppearanceSettings";
import { CoordinatorLetterSettings } from "@/components/InternshipLetter";
import { ChangePasswordPanel } from "@/components/ChangePassword";
